// 细粒度锁（分片）
type Shard struct {
    mu   sync.Mutex
    data map[string]int
}

type ShardedMap []*Shard

func (m ShardedMap) GetShard(key string) *Shard {
    // 哈希分片
    hash := fnv.New32a()
    hash.Write([]byte(key))
    shardIndex := hash.Sum32() % uint32(len(m))
    return m[shardIndex]
}
